const input = $input.first().json;

// ── Validate required fields ──
if (!input) {
  throw new Error('No input data received');
}

// ── Core scenario logic ──
// Scenario: Daily: new leads count + conversion rate → Slack notification
const output = {
  ...input,
  processed: true,
  processedAt: new Date().toISOString(),
  domain: 'reporting',
  scenario: 'Daily: new leads count + conversion rate → Slack notification',
  gridhandVersion: '1.0',
};

return [{ json: output }];

